      const mock = "<script>window.PDC_MOCK=" + JSON.stringify(Studio.genMock(sp)) + ";</scr" + "ipt>";
      html = html.replace("window.STUDIO_AUTOBOOT=false;", "window.STUDIO_AUTOBOOT=false;");
