    // ---- cascading filters: a parameterized filter reloads on upstream change ----
    const casc = await page.evaluate(async () => {
      const spec = await fetch("data/examples/studio-cost.studio.json").then((r) => r.json());
      // two filters: ds (plain) + a parameterized one (cost_by_source declares ds, sens)
      spec.filters = [
        { id: "ds", label: "Source", da: "cost_by_source", valueCol: "src", textCol: "src", allLabel: "All", def: "%" },
        { id: "sens", label: "Sensitivity", da: "cost_by_sens", valueCol: "sens", textCol: "sens", allLabel: "All", def: "%" }
      ];
      window.__studioLoad(spec);
      const d = await window.__waitForPreview((doc) => doc.querySelectorAll("#ctrls select.pdc-sel").length === 2);
      var sels = d.querySelectorAll("#ctrls select.pdc-sel");
      var before = sels.length;
      // change the first filter → triggers load + cascade without error
      if (sels[0]) { sels[0].value = sels[0].options[1] ? sels[0].options[1].value : sels[0].value; sels[0].dispatchEvent(new Event("change")); }
      const d2 = await window.__waitForPreview((doc) => {
        var s = doc.querySelectorAll("#ctrls select.pdc-sel");
        return s.length === 2 && s[1].options.length >= 2;
      });
      var after = d2.querySelectorAll("#ctrls select.pdc-sel").length;
      var opts = d2.querySelector("#ctrls select.pdc-sel") ? d2.querySelectorAll("#ctrls select.pdc-sel")[1].options.length : 0;
      return { before: before, after: after, downstreamOpts: opts, err: /Render error|Could not load/.test(d2.querySelector("#content").textContent) };
    });
    ok("cascading filters: both selects present, downstream repopulated, no errors", casc.before === 2 && casc.after === 2 && casc.downstreamOpts >= 2 && !casc.err, JSON.stringify(casc));

    // ---- panel duplicate / delete (canvas + inspector) ----
    console.log("\n• panel duplicate / delete");
    await page.evaluate(async () => { const spec = await fetch("data/examples/studio-cost.studio.json").then((r) => r.json()); window.__studioLoad(spec); });
    // window.__STUDIO_STATE.spec is set synchronously by __studioLoad — no wait needed here.
    const pcount0 = await page.evaluate(() => window.__STUDIO_STATE.spec.panels.length);
    const pvp = page.frames().find((f) => f !== page.mainFrame());
    // The dup/del click's effect on window.__STUDIO_STATE (parent page) round-trips through
    // the preview iframe's postMessage, so poll for the expected panel count instead of a
    // fixed wait — was observed to flake on slower machines (Track L sweep, 2026-07-02).
    // Track H sweep (2026-07-04): `force:true` skips Playwright's normal actionability
    // auto-wait/retry (that's the whole point of force), so on a loaded sandbox the click
    // could fire while the panel row was still mid-reflow from the PRIOR action and fail
    // outright with "Element is not visible" instead of retrying — confirmed independently
    // on origin/main HEAD with zero other changes (three different failure shapes across
    // three runs of the identical commit). Explicitly wait for the target to be visible
    // first (real auto-retry), THEN force-click (still needed in case something transient
    // overlaps it) — belt and suspenders. Also widened the post-click poll to 8000ms; both
    // assertions below are still an exact panel-count match, unchanged.
    // Track L (test-health lens, round 2): even the visible-wait + force-click combo above
    // still hit "Element is not visible" once in a live run — a `waitFor` resolving true
    // doesn't guarantee the element is STILL visible by the time `.click()` itself samples
    // its bounding box a moment later (the row can be mid-reflow from the fetch/__studioLoad
    // just above it). `force:true` skips the actionability retry loop entirely, so a single
    // bad sample throws instead of retrying — wrap both actions in a tiny click-retry so a
    // one-frame flicker gets a second real attempt instead of failing the whole run.
    async function retryForceClick(locator, attempts) {
      for (let i = 0; i < attempts; i++) {
        try {
          await locator.waitFor({ state: "visible", timeout: 8000 });
          await locator.click({ force: true, timeout: 3000 });
          return;
        } catch (e) {
          if (i === attempts - 1) throw e;
          await page.waitForTimeout(250);
        }
      }
    }
    const dupBtn = pvp.locator('[data-panel-id] .sr-act[data-act="dup"]').first();
    await retryForceClick(dupBtn, 3);
    await page.waitForFunction((n) => window.__STUDIO_STATE.spec.panels.length === n, pcount0 + 1, { timeout: 8000 }).catch(() => {});
    const pcount1 = await page.evaluate(() => window.__STUDIO_STATE.spec.panels.length);
    ok("canvas ⧉ duplicates a panel", pcount1 === pcount0 + 1, pcount0 + "→" + pcount1);
    const delBtn = pvp.locator('[data-panel-id] .sr-act[data-act="del"]').first();
    await retryForceClick(delBtn, 3);
    await page.waitForFunction((n) => window.__STUDIO_STATE.spec.panels.length === n, pcount1 - 1, { timeout: 8000 }).catch(() => {});
    const pcount2 = await page.evaluate(() => window.__STUDIO_STATE.spec.panels.length);
    ok("canvas × deletes a panel", pcount2 === pcount1 - 1, pcount1 + "→" + pcount2);
    // inspector duplicate
