    ok("N-AI: '📍 Add callout' button appears in the Insight section when a notable point is found",
      calloutUI.hasBtn === !!calloutUI.expected, JSON.stringify(calloutUI));
    ok("N-AI: clicking '📍 Add callout' sets p.callout to the exact x/y Studio.notablePoint computed for this panel",
      !calloutUI.expected || (calloutUI.callout && calloutUI.callout.x === calloutUI.expected.x && calloutUI.callout.y === calloutUI.expected.y &&
        calloutUI.callout.text === (calloutUI.expected.kind === "outlier" ? "Outlier" : "Biggest move")),
      JSON.stringify(calloutUI));

    // ---- Z7/N-AI follow-up: correlation insight for scatter (two-variable) charts ----
    console.log("\n• scatter correlation insight");
    const scatCorrUnit = await page.evaluate(() => {
      const cols = ["x", "y"];
      const rows = [[1, 2], [2, 4], [3, 6], [4, 8], [5, 10], [6, 12]];
      return Studio.computeCorrelation(cols, rows, "x", "y");
    });
    ok("Studio.computeCorrelation reports a strong positive correlation for perfectly linear data",
      /strong positive/.test(scatCorrUnit) && /r = 1\.00/.test(scatCorrUnit), scatCorrUnit);
    const scatCorrNone = await page.evaluate(() => Studio.computeCorrelation(["x", "y"], [[1, 2]], "x", "y"));
    ok("Studio.computeCorrelation returns null with fewer than 3 valid points", scatCorrNone === null, String(scatCorrNone));
    const scatCorrUI = await page.evaluate(function () {
      var spec = window.__STUDIO_STATE.spec;
      var p = spec.panels[0];
      var prevChart = JSON.parse(JSON.stringify(p.chart));
      var da = Studio.daById(spec, p.chart.da);
      var sd = Studio.sampleRows(da);
      var numCols = sd.cols.filter(function (c, i) { return !isNaN(Number(sd.rows[0][i])); });
      p.chart.type = "scatter";
      p.chart.map = { xCol: numCols[0], yCol: numCols[1] || numCols[0] };
      window.__studioSelect({ kind: "panel", id: p.id });
      var sec = [].slice.call(document.querySelectorAll("#inspBody .insp-sec h4")).filter(function (h) { return h.textContent.trim() === "Insight"; })[0];
      var found = !!sec, hasText = false;
      if (sec) {
        var box = sec.closest(".insp-sec").querySelector(".insight-box");
        hasText = !!box && box.textContent.length > 15;
      }
      p.chart = prevChart;
      window.__studioSelect(null);
      window.__studioRenderInspector();
      return { found: found, hasText: hasText };
    });
    ok("Insight section shows a correlation read for a scatter panel with xCol/yCol bound", scatCorrUI.found && scatCorrUI.hasText, JSON.stringify(scatCorrUI));

    // ---- N-AI: smart chart recommender ----
    console.log("\n• smart chart recommender");
    const recoUnit = await page.evaluate(() => {
      const dateCols = ["month", "revenue"];
      const dateRows = [["Jan", 100], ["Feb", 110], ["Mar", 120], ["Apr", 130]];
      const dateReco = Studio.recommendCharts(dateCols, dateRows).map(r => r.type);
      const catCols = ["region", "sales"];
      const catRows = [["East", 10], ["West", 20], ["North", 15]];
      const catReco = Studio.recommendCharts(catCols, catRows).map(r => r.type);
      const wideCols = ["a", "b", "c", "d", "e"];
      const wideRows = [["x", 1, 2, 3, 4]];
      const wideReco = Studio.recommendCharts(wideCols, wideRows).map(r => r.type);
      const emptyReco = Studio.recommendCharts([], []);
      return { dateReco, catReco, wideReco, emptyReco };
    });
    ok("Studio.recommendCharts suggests line for a date + numeric column", recoUnit.dateReco.indexOf("line") >= 0, JSON.stringify(recoUnit.dateReco));
    ok("Studio.recommendCharts suggests bars + donut for a low-cardinality category + numeric column", recoUnit.catReco.indexOf("bars") >= 0 && recoUnit.catReco.indexOf("donut") >= 0, JSON.stringify(recoUnit.catReco));
    ok("Studio.recommendCharts suggests table for a wide (4+ column) query", recoUnit.wideReco.indexOf("table") >= 0, JSON.stringify(recoUnit.wideReco));
    ok("Studio.recommendCharts returns an empty array with no rows", Array.isArray(recoUnit.emptyReco) && recoUnit.emptyReco.length === 0, JSON.stringify(recoUnit.emptyReco));
    const recoUI = await page.evaluate(function () {
      var spec = window.__STUDIO_STATE.spec;
      var p = spec.panels[0];
      var prevChart = JSON.parse(JSON.stringify(p.chart));
      window.__studioSelect({ kind: "panel", id: p.id });
      var strip = document.querySelector("#inspBody .chart-reco");
      var chips = strip ? [].slice.call(strip.querySelectorAll(".chart-reco-chip")) : [];
      var result = { found: !!strip, chipCount: chips.length, hasWhy: chips.length > 0 && !!chips[0].title };
      var other = chips.filter(function (c) { return c.dataset.type !== prevChart.type; })[0];
      if (other) {
        other.click();
        result.typeChanged = p.chart.type === other.dataset.type && p.chart.type !== prevChart.type;
      } else if (chips.length) {
        result.typeChanged = true; // every recommendation already matches the current type — nothing to prove
      }
      p.chart = prevChart;
      window.__studioSelect(null);
      window.__studioRenderInspector();
      return result;
    });
    ok("Recommended-charts strip appears in the panel inspector for a data-bound panel", recoUI.found && recoUI.chipCount > 0, JSON.stringify(recoUI));
    ok("Each recommendation chip carries a 'why' tooltip", recoUI.hasWhy, JSON.stringify(recoUI));
    ok("Clicking a recommendation chip changes the panel's chart type", recoUI.typeChanged, JSON.stringify(recoUI));

    // ---- Pentaho connections: Kettle XML, CDA parser, client, UI ----
    console.log("\n• Pentaho server connections");
    const ph = await page.evaluate(() => {
      var xml = "<slaveserver><name>Prod BA</name><hostname>pentaho.acme.com</hostname><port>8443</port><webAppName>pentaho</webAppName><username>admin</username><password>secret</password><sslMode>Y</sslMode></slaveserver>";
      var conns = Studio.kettle.parse(xml);
      var ser = Studio.kettle.serialize(conns);
      var reparse = Studio.kettle.parse(ser);
      var cda = Studio.parseCDA('<?xml version="1.0"?><CDADescriptor><DataSources><Connection id="pdc" type="sql.jndi"><Jndi>PDC-BIDB-EXT</Jndi></Connection></DataSources><DataAccess id="q1" cache="true" cacheDuration="120"><Name>Q1</Name><Parameters><Parameter name="ds" type="String" default="%"/></Parameters><Query><![CDATA[ SELECT a AS src, SUM(b) AS total FROM t WHERE x LIKE ${ds} GROUP BY 1 ]]></Query></DataAccess></CDADescriptor>');
      var cl = Studio.PentahoClient(conns[0]);
      return { n: conns.length, scheme: conns[0].scheme, host: conns[0].hostname, port: conns[0].port, reN: reparse.length, reHost: reparse[0].hostname,
        base: cl.base(), content: cl.contentUrl("/public/x/y.cda"), tree: cl.treeUrl("/public", "*.cda"), pub: cl.publishUrl(), dq: cl.doQueryUrl("/p/q.cda", "kpi", { ds: "%" }),
        cdaJndi: cda.connection.jndi, cdaDa: cda.dataAccesses[0].id, cdaCols: cda.dataAccesses[0].columns.join(","), cdaParam: (cda.dataAccesses[0].params[0] || {}).name };
    });
    ok("Kettle XML parses (https→port, ssl)", ph.n === 1 && ph.scheme === "https" && ph.host === "pentaho.acme.com" && ph.port === "8443", JSON.stringify(ph).slice(0, 120));
    ok("Kettle XML round-trips", ph.reN === 1 && ph.reHost === "pentaho.acme.com");
    ok("CDA parser extracts da/cols/params", ph.cdaJndi === "PDC-BIDB-EXT" && ph.cdaDa === "q1" && ph.cdaCols === "src,total" && ph.cdaParam === "ds", ph.cdaCols);
    ok("client builds Pentaho REST urls", ph.base === "https://pentaho.acme.com:8443/pentaho" && /\/api\/repos\/:public:x:y\.cda\/content$/.test(ph.content) && /\/plugin\/cda\/api\/doQuery\?/.test(ph.dq) && /\/api\/repo\/publish\/publishfile$/.test(ph.pub), ph.base);

    // connections UI: open ⚙ Servers → Import Kettle XML → Use
