    ok("N-DEV: the editable spec.title itself keeps the raw {{key}} token (substitution happens only at render)",
      tvRender.rawTitleUntouched, JSON.stringify(tvRender));

    // Inspector: Template variables section — add/edit/remove rows
    await page.evaluate(function () { window.__STUDIO_STATE.selection = null; window.__studioRenderInspector(); });
    await page.waitForTimeout(100);
    const tvInspAdd = await page.evaluate(function () {
      var h4s = [].slice.call(document.querySelectorAll("#inspBody h4"));
      var sec = h4s.filter(function (h) { return h.textContent.indexOf("Template variables") >= 0; })[0];
      var box = sec ? sec.closest(".insp-sec") : null;
      var addBtn = box ? [].slice.call(box.querySelectorAll("button")).filter(function (b) { return /Add variable/.test(b.textContent); })[0] : null;
      if (addBtn) addBtn.click();
      return { sectionPresent: !!sec, rowCount: window.__STUDIO_STATE.spec.templateVars.length };
    });
    ok("N-DEV: Dashboard inspector has a 'Template variables' section, and '+ Add variable' pushes a new row",
      tvInspAdd.sectionPresent && tvInspAdd.rowCount === 2, JSON.stringify(tvInspAdd)); // region (from tvRender above) + the new row

    const tvInspEdit = await page.evaluate(function () {
      var h4s = [].slice.call(document.querySelectorAll("#inspBody h4"));
      var sec = h4s.filter(function (h) { return h.textContent.indexOf("Template variables") >= 0; })[0];
      var box = sec.closest(".insp-sec");
      var rows = box.querySelectorAll(".dsb-sqb-inp");
      var lastKeyInp = rows[rows.length - 2], lastValInp = rows[rows.length - 1];
      lastKeyInp.value = "team"; lastKeyInp.dispatchEvent(new Event("change", { bubbles: true }));
      lastValInp.value = "Growth"; lastValInp.dispatchEvent(new Event("input", { bubbles: true }));
      return { vars: window.__STUDIO_STATE.spec.templateVars.slice() };
    });
    ok("N-DEV: editing the key/value inputs writes back into spec.templateVars",
      tvInspEdit.vars[1].key === "team" && tvInspEdit.vars[1].value === "Growth", JSON.stringify(tvInspEdit));

    const tvInspRemove = await page.evaluate(function () {
      var h4s = [].slice.call(document.querySelectorAll("#inspBody h4"));
      var sec = h4s.filter(function (h) { return h.textContent.indexOf("Template variables") >= 0; })[0];
      var box = sec.closest(".insp-sec");
      var delBtns = box.querySelectorAll('button[title="Remove variable"]');
      delBtns[delBtns.length - 1].click();
      return { rowCount: window.__STUDIO_STATE.spec.templateVars.length };
    });
    ok("N-DEV: the remove button deletes that row from spec.templateVars", tvInspRemove.rowCount === 1, JSON.stringify(tvInspRemove));
    await page.evaluate(function () { window.__STUDIO_STATE.spec.title = window.__tvOrigTitle; window.__STUDIO_STATE.spec.templateVars = []; });
    await page.waitForTimeout(150);

    // N-DEV follow-up: {{key}} template vars now also resolve in panel Title/Note (previously
    // Title/Subtitle only), rendered via studio-render.js's renderGrid (shared by preview + export).
    const tvPanelRender = await page.evaluate(async function () {
      var freshSpec = await fetch("data/examples/studio-cost.studio.json").then(function (r) { return r.json(); });
      freshSpec.templateVars = [{ key: "region", value: "APAC" }];
      freshSpec.panels[0].title = "{{region}} Panel Title";
      freshSpec.panels[0].note = "{{region}} panel note";
      window.__studioLoad(freshSpec);
      return true;
    });
    await page.waitForTimeout(500);
    const tvPanelRendered = await page.evaluate(function () {
      var ifr = document.getElementById("preview");
      var doc = ifr && ifr.contentWindow && ifr.contentWindow.document;
      var titleEl = doc && doc.querySelector("[data-panel-id] .pdc-h-t");
      var noteEl = doc && doc.querySelector("[data-panel-id] .pdc-panel-note");
      var titleNode = titleEl && titleEl.firstChild; // ignore a possible trailing info-dot icon appended after the text
      return {
        titleText: titleEl ? (titleNode && titleNode.nodeType === 3 ? titleNode.textContent : titleEl.textContent).trim() : null,
        noteText: noteEl ? noteEl.textContent.trim() : null,
        rawTitleUntouched: window.__STUDIO_STATE.spec.panels[0].title
      };
    });
    ok("N-DEV: {{key}} resolves in a panel's rendered Title", tvPanelRender && tvPanelRendered.titleText === "APAC Panel Title", JSON.stringify(tvPanelRendered));
    ok("N-DEV: {{key}} resolves in a panel's rendered Note", tvPanelRendered.noteText === "APAC panel note", JSON.stringify(tvPanelRendered));
    ok("N-DEV: the underlying spec.panels[i].title keeps the raw {{key}} token (substitution happens only at render)",
      tvPanelRendered.rawTitleUntouched === "{{region}} Panel Title", JSON.stringify(tvPanelRendered));

    // Double-click-to-rename must edit the RAW template string, not the resolved display text —
    // otherwise committing the rename would silently bake the resolved value back into the spec.
    const tvPanelFrame = page.frames().find((f) => f !== page.mainFrame());
    await tvPanelFrame.locator("[data-panel-id] .pdc-h-t").first().dblclick();
    await page.waitForTimeout(120);
    const tvRenameValue = await tvPanelFrame.evaluate(function () {
      var inp = document.querySelector(".sr-rename");
      return inp ? inp.value : null;
    });
    await page.keyboard.press("Escape");
    await page.waitForTimeout(100);
    ok("N-DEV: double-click rename on a panel title starts from the raw {{key}} token, not the resolved text",
      tvRenameValue === "{{region}} Panel Title", "got: " + tvRenameValue);

    // Restore spec to clean state
    await page.evaluate(async function () {
      var freshSpec = await fetch("data/examples/studio-cost.studio.json").then(function (r) { return r.json(); });
      window.__studioLoad(freshSpec);
    });
    await page.waitForTimeout(200);

    // N-DEV follow-up: named, reusable template-variable sets — save the current {{key}}→value
    // rows under a name, then apply that same set to any dashboard.
    await page.evaluate(function () { try { localStorage.removeItem("studio-templatevar-sets"); } catch (e) {} window.__STUDIO_STATE.spec.templateVars = []; window.__STUDIO_STATE.selection = null; window.__studioRenderInspector(); });
    await page.waitForTimeout(100);
    const tvSetsEmpty = await page.evaluate(function () {
      var h4s = [].slice.call(document.querySelectorAll("#inspBody h4"));
      var sec = h4s.filter(function (h) { return h.textContent.indexOf("Template variables") >= 0; })[0];
      var box = sec.closest(".insp-sec");
      return { hasSelect: !!box.querySelector("select"), sets: window.__studioTemplateVarSets().length };
    });
    ok("N-DEV: no saved template-variable sets initially, so no picker <select> renders",
      !tvSetsEmpty.hasSelect && tvSetsEmpty.sets === 0, JSON.stringify(tvSetsEmpty));

    const tvSetSaved = await page.evaluate(function () {
      var h4s = [].slice.call(document.querySelectorAll("#inspBody h4"));
      var sec = h4s.filter(function (h) { return h.textContent.indexOf("Template variables") >= 0; })[0];
      var box = sec.closest(".insp-sec");
      var addBtn = [].slice.call(box.querySelectorAll("button")).filter(function (b) { return /Add variable/.test(b.textContent); })[0];
      addBtn.click();
      var rows = box.querySelectorAll(".dsb-sqb-inp");
      var keyInp = rows[rows.length - 2], valInp = rows[rows.length - 1];
      keyInp.value = "region"; keyInp.dispatchEvent(new Event("change", { bubbles: true }));
      valInp.value = "APAC"; valInp.dispatchEvent(new Event("input", { bubbles: true }));
      var nameInp = [].slice.call(box.querySelectorAll('input[type="text"]')).filter(function (i) { return /Set name/.test(i.placeholder || ""); })[0];
      nameInp.value = "APAC set";
      var saveBtn = [].slice.call(box.querySelectorAll("button")).filter(function (b) { return /Save current as/.test(b.textContent); })[0];
      saveBtn.click();
      return { sets: window.__studioTemplateVarSets() };
    });
    ok("N-DEV: 'Save current as…' captures the current template variables under a named set",
      tvSetSaved.sets.length === 1 && tvSetSaved.sets[0].name === "APAC set" &&
      tvSetSaved.sets[0].vars.length === 1 && tvSetSaved.sets[0].vars[0].key === "region" && tvSetSaved.sets[0].vars[0].value === "APAC",
      JSON.stringify(tvSetSaved));

    // Mutate templateVars away, then Apply the saved set to prove it restores the snapshot
    await page.evaluate(function () { window.__STUDIO_STATE.spec.templateVars = [{ key: "other", value: "X" }]; window.__studioRenderInspector(); });
    await page.waitForTimeout(100);
    const tvSetApplied = await page.evaluate(function () {
      var h4s = [].slice.call(document.querySelectorAll("#inspBody h4"));
      var sec = h4s.filter(function (h) { return h.textContent.indexOf("Template variables") >= 0; })[0];
      var box = sec.closest(".insp-sec");
      var applyBtn = [].slice.call(box.querySelectorAll("button")).filter(function (b) { return b.textContent.trim() === "Apply"; })[0];
      applyBtn.click();
      return { vars: window.__STUDIO_STATE.spec.templateVars.slice() };
    });
    ok("N-DEV: Apply on a saved template-variable set restores its {key,value} rows onto the dashboard",
      tvSetApplied.vars.length === 1 && tvSetApplied.vars[0].key === "region" && tvSetApplied.vars[0].value === "APAC",
      JSON.stringify(tvSetApplied));

    const tvSetsInKeys = await page.evaluate(function () { return window.__studioImportSettingsKeys.indexOf("studio-templatevar-sets") >= 0; });
    ok("N-DEV: template-variable sets are included in Settings export/import keys", tvSetsInKeys, String(tvSetsInKeys));

    await page.evaluate(function () { window.__studioRenderInspector(); });
    await page.waitForTimeout(100);
    const tvSetDeleted = await page.evaluate(function () {
      var h4s = [].slice.call(document.querySelectorAll("#inspBody h4"));
      var sec = h4s.filter(function (h) { return h.textContent.indexOf("Template variables") >= 0; })[0];
      var box = sec.closest(".insp-sec");
      var delBtn = box.querySelector('button[title="Delete this saved set"]');
      if (delBtn) delBtn.click();
      return { sets: window.__studioTemplateVarSets().length };
    });
    ok("N-DEV: deleting a saved template-variable set removes it", tvSetDeleted.sets === 0, JSON.stringify(tvSetDeleted));

    await page.evaluate(function () {
      window.__STUDIO_STATE.spec.templateVars = [];
      try { localStorage.removeItem("studio-templatevar-sets"); } catch (e) {}
      window.__studioRenderInspector();
    });
    await page.waitForTimeout(100);

    // ── N-FUN: Build-completeness meter ─────────────────────────────────────
    console.log("\n• N-FUN: Build-completeness meter");
    const bcApi = await page.evaluate(function () {
      var empty = Studio.dashboardCompleteness(Studio.emptySpec());
      var full = Studio.dashboardCompleteness({
        title: "My Real Dashboard", panels: [{}], kpis: [{}], filters: [{}], themeColor: "#1a7a4a",
      });
      return {
        emptyDone: empty.done, emptyTotal: empty.total,
        fullDone: full.done, fullTotal: full.total,
      };
    });
    ok("N-FUN: Studio.dashboardCompleteness scores 0/5 for a blank spec and 5/5 once title/panel/kpi/filter/style are all present",
      bcApi.emptyDone === 0 && bcApi.emptyTotal === 5 && bcApi.fullDone === 5 && bcApi.fullTotal === 5, JSON.stringify(bcApi));

    await page.evaluate(function () { window.__STUDIO_STATE.selection = null; window.__studioRenderInspector(); });
    await page.waitForTimeout(100);
    const bcDom = await page.evaluate(function () {
      var bc = document.querySelector(".build-comp");
      var ring = bc ? bc.querySelector(".bc-ring-fg") : null;
      var txt = bc ? bc.querySelector(".bc-txt").textContent : "";
      var list = bc ? bc.querySelectorAll(".bc-list li").length : -1;
      return { present: !!bc, hasRing: !!ring, txt: txt, remainingCount: list };
    });
    ok("N-FUN: dashboard inspector shows a Build progress ring + remaining-items checklist for the loaded (incomplete) flagship dashboard",
      bcDom.present && bcDom.hasRing && /Build progress: \d\/5/.test(bcDom.txt) && bcDom.remainingCount >= 0, JSON.stringify(bcDom));

    const bcCelebrate = await page.evaluate(function () {
      var sp = window.__STUDIO_STATE.spec;
      sp.filters = sp.filters && sp.filters.length ? sp.filters : [{ id: "bcf1", label: "Test", col: "src", da: (sp.cda.dataAccesses[0] || {}).id || "" }];
      sp.themeColor = "#1a7a4a";
      window.__STUDIO_STATE.selection = null; window.__studioRenderInspector();
      var bc = document.querySelector(".build-comp");
      return { txt: bc.querySelector(".bc-txt").textContent, listCount: bc.querySelectorAll(".bc-list li").length };
    });
    ok("N-FUN: once every milestone is met the meter shows 5/5 + a celebratory line, no leftover checklist",
      /Build progress: 5\/5/.test(bcCelebrate.txt) && bcCelebrate.listCount === 0, JSON.stringify(bcCelebrate));

    // ── N-DATA innovation idea ("dashboard health score", first slice): Studio.validate() now
    // flags a declared data access that no panel/KPI actually references — dead config a builder
    // would otherwise never notice. Pure model-level check, exercised directly (no DOM).
    console.log("\n• N-DATA: orphaned data-access check (dashboard health score, first slice)");
    const orphanDa = await page.evaluate(function () {
      var used = Studio.validate({
        name: "ok-name", title: "T", panels: [{ id: "p1", chart: { da: "usedDa" } }], kpis: [],
        cda: { dataAccesses: [{ id: "usedDa", name: "usedDa" }] }
      });
      var orphaned = Studio.validate({
        name: "ok-name", title: "T", panels: [{ id: "p1", chart: { da: "usedDa" } }], kpis: [],
        cda: { dataAccesses: [{ id: "usedDa", name: "usedDa" }, { id: "deadDa", name: "Old Sales Query" }] }
      });
      var usedByKpi = Studio.validate({
        name: "ok-name", title: "T", panels: [], kpis: [{ da: "kpiDa" }],
        cda: { dataAccesses: [{ id: "kpiDa", name: "kpiDa" }] }
      });
      return {
        usedHasNoOrphanIssue: !used.some(function (i) { return /declared but not used/.test(i.msg); }),
        orphanedFlagsDeadDa: orphaned.some(function (i) { return i.level === "info" && /“Old Sales Query” is declared but not used/.test(i.msg); }),
        orphanedDoesNotFlagUsedDa: !orphaned.some(function (i) { return /“usedDa” is declared but not used/.test(i.msg); }),
        kpiBoundDaNotFlagged: !usedByKpi.some(function (i) { return /declared but not used/.test(i.msg); })
      };
    });
    ok("N-DATA: a data access bound to a panel is not flagged as orphaned", orphanDa.usedHasNoOrphanIssue, JSON.stringify(orphanDa));
    ok("N-DATA: a data access bound to NO panel/KPI is flagged as an info-level 'declared but not used' issue", orphanDa.orphanedFlagsDeadDa, JSON.stringify(orphanDa));
    ok("N-DATA: the actually-used data access in that same spec is not also flagged", orphanDa.orphanedDoesNotFlagUsedDa, JSON.stringify(orphanDa));
    ok("N-DATA: a data access bound to a KPI (not a panel) is also recognized as used", orphanDa.kpiBoundDaNotFlagged, JSON.stringify(orphanDa));

    // N-DATA follow-up: found + fixed two false positives in that same "declared but not used"
    // check while closing the "still open" data-quality-watchdog half of this idea — a DA bound
    // only to a FILTER, or only feeding a compound (join/union) DA as its leftId/rightId source,
    // was wrongly flagged "unused" even though it genuinely is.
    const orphanFixes = await page.evaluate(function () {
      var filterBound = Studio.validate({
        name: "ok-name", title: "T", panels: [], kpis: [], filters: [{ id: "f1", da: "filterDa" }],
        cda: { dataAccesses: [{ id: "filterDa", name: "filterDa" }] }
      });
      var joinDa = Studio.newCompoundDA("join"); joinDa.id = "joinDa"; joinDa.leftId = "leftDa"; joinDa.rightId = "rightDa";
      var compoundSpec = Studio.validate({
        name: "ok-name", title: "T", panels: [{ id: "p1", chart: { da: "joinDa" } }], kpis: [], filters: [],
        cda: { dataAccesses: [{ id: "leftDa", name: "leftDa" }, { id: "rightDa", name: "rightDa" }, joinDa] }
      });
      return {
        filterBoundNotFlagged: !filterBound.some(function (i) { return /declared but not used/.test(i.msg); }),
        compoundSourcesNotFlagged: !compoundSpec.some(function (i) { return /declared but not used/.test(i.msg); })
      };
    });
    ok("N-DATA: a data access bound only to a filter is not flagged as orphaned", orphanFixes.filterBoundNotFlagged, JSON.stringify(orphanFixes));
    ok("N-DATA: a compound (join/union) DA's leftId/rightId sources are not flagged as orphaned even with no panel bound directly to them",
      orphanFixes.compoundSourcesNotFlagged, JSON.stringify(orphanFixes));

    // N-DATA follow-up: closes the "broken drill-through/detail-drawer target" health-score item
    // (was left "still open" at v309) — a panel's Detail drawer (p.detail.da) targets a DA id
    // INSIDE the spec, unlike drill-through's always-external URL, so it's a real, checkable
    // target that can go stale if the DA it points at gets deleted or renamed.
    const detailTarget = await page.evaluate(function () {
      var healthy = Studio.validate({
        name: "ok-name", title: "T",
        panels: [{ id: "p1", chart: { da: "usedDa" }, detail: { da: "usedDa" } }], kpis: [],
        cda: { dataAccesses: [{ id: "usedDa", name: "usedDa" }] }
      });
      var broken = Studio.validate({
        name: "ok-name", title: "T",
        panels: [{ id: "p1", title: "Sales by region", chart: { da: "usedDa" }, detail: { da: "deletedDa" } }], kpis: [],
        cda: { dataAccesses: [{ id: "usedDa", name: "usedDa" }] }
      });
      var noDetail = Studio.validate({
        name: "ok-name", title: "T", panels: [{ id: "p1", chart: { da: "usedDa" } }], kpis: [],
        cda: { dataAccesses: [{ id: "usedDa", name: "usedDa" }] }
      });
      return {
        healthyNotFlagged: !healthy.some(function (i) { return /Detail drawer points to a data access/.test(i.msg); }),
        brokenIsFlagged: broken.some(function (i) { return i.level === "warn" && /“Sales by region”.*Detail drawer points to a data access that no longer exists/.test(i.msg); }),
        noDetailNotFlagged: !noDetail.some(function (i) { return /Detail drawer points to a data access/.test(i.msg); })
      };
    });
    ok("N-DATA: a panel with a healthy Detail drawer target is not flagged", detailTarget.healthyNotFlagged, JSON.stringify(detailTarget));
    ok("N-DATA: a panel whose Detail drawer points at a deleted/renamed data access is flagged (warn)", detailTarget.brokenIsFlagged, JSON.stringify(detailTarget));
    ok("N-DATA: a panel with no Detail drawer configured at all is not flagged", detailTarget.noDetailNotFlagged, JSON.stringify(detailTarget));

    // N-DATA: closes the "still open" data-quality-watchdog half of the dashboard health score
    // idea — Studio.validate() now also runs the existing watchdog (v260/v261) over every bound
    // (non-orphaned) DA's own sample rows, surfacing each issue as a warn-level Checks note.
    const dqWatchdog = await page.evaluate(function () {
      var origSample = Studio.sampleRows;
      Studio.sampleRows = function () { return { cols: ["x"], rows: [["a"], ["a"], [null]] }; };
      var dirty = Studio.validate({
        name: "ok-name", title: "T", panels: [{ id: "p1", chart: { da: "dirtyDa" } }], kpis: [], filters: [],
        cda: { dataAccesses: [{ id: "dirtyDa", name: "dirtyDa", columns: ["x"] }] }
      });
      var orphanedNotProfiled = Studio.validate({
        name: "ok-name", title: "T", panels: [], kpis: [], filters: [],
        cda: { dataAccesses: [{ id: "dirtyDa", name: "dirtyDa", columns: ["x"] }] }
      });
      Studio.sampleRows = origSample;
      return {
        dirtyFlagsQuality: dirty.some(function (i) { return i.level === "warn" && /“dirtyDa”: “x” has 1 blank/.test(i.msg); }),
        orphanedSkipsQualityCheck: !orphanedNotProfiled.some(function (i) { return /blank/.test(i.msg); })
      };
    });
    ok("N-DATA: a bound DA's data quality issues (from Studio.dataQualityIssues) surface as warn-level Checks notes",
      dqWatchdog.dirtyFlagsQuality, JSON.stringify(dqWatchdog));
    ok("N-DATA: an orphaned DA isn't also profiled for quality (avoids piling a second, redundant note on top of 'declared but not used')",
      dqWatchdog.orphanedSkipsQualityCheck, JSON.stringify(dqWatchdog));

    // Architecture-gap finding: a dashboard using one of the four credential-based direct-query
    // connectors gets a warn-level Checks note that it has no live query path once exported/
    // deployed. DuckDB/SQLite are exempt (Z14 fix, same run as this test update): they now have a
    // real runtime path via studio-render.js's PDC.cda dispatch, see the dedicated test below.
    const directConnWarn = await page.evaluate(function () {
      function specWith(kind) {
        return {
          name: "ok-name", title: "T", panels: [{ id: "p1", chart: { da: "d1" } }], kpis: [], filters: [],
          cda: { dataAccesses: [{ id: "d1", name: "sfDa", kind: kind, columns: ["x"] }] }
        };
      }
      var snowflake = Studio.validate(specWith("snowflake"));
      var duckdb = Studio.validate(specWith("duckdb"));
      var pentaho = Studio.validate(specWith("sql.jndi"));
      var orphanedSnowflake = Studio.validate({
        name: "ok-name", title: "T", panels: [], kpis: [], filters: [],
        cda: { dataAccesses: [{ id: "d1", name: "sfDa", kind: "snowflake", columns: ["x"] }] }
      });
      return {
        snowflakeFlagged: snowflake.some(function (i) { return i.level === "warn" && /“sfDa” \(Snowflake\) has no live query path/.test(i.msg); }),
        duckdbNotFlagged: !duckdb.some(function (i) { return /no live query path/.test(i.msg); }),
        pentahoNotFlagged: !pentaho.some(function (i) { return /no live query path/.test(i.msg); }),
        orphanedNotDoubleFlagged: !orphanedSnowflake.some(function (i) { return /no live query path/.test(i.msg); })
      };
    });
    ok("N-DATA: a bound Snowflake (or Databricks/BigQuery/Generic SQL) DA gets a warn-level 'no live query path once exported' Checks note",
      directConnWarn.snowflakeFlagged, JSON.stringify(directConnWarn));
    ok("Z14: a bound DuckDB/SQLite DA is NOT flagged — they have a real runtime query path once exported now", directConnWarn.duckdbNotFlagged, JSON.stringify(directConnWarn));
    ok("N-DATA: a plain Pentaho SQL/MDX DA is NOT flagged with the direct-connector export warning", directConnWarn.pentahoNotFlagged, JSON.stringify(directConnWarn));
    ok("N-DATA: an orphaned direct-connector DA only gets the 'declared but not used' note, not also the export warning", directConnWarn.orphanedNotDoubleFlagged, JSON.stringify(directConnWarn));

    // Z14 architecture-gap FIX (2026-07-04, same run as the test update above): the exported
    // Dashboard Framework now has a real runtime query path for DuckDB/SQLite. Verify (1) lean
    // bundling — the connector façade is only inlined when that DA kind is actually used — and
    // (2) studio-render.js's PDC.cda dispatch genuinely reaches Studio.DuckDB/SQLiteHttp.query()
    // once no PDC_MOCK data is present (i.e. a real deployment), not a Pentaho CDA fetch that
    // would 404 for a DA with no server-side definition.
    console.log("\n• Z14 fix: exported dashboards can now query DuckDB/SQLite live");
    const z14Bundling = await page.evaluate(function () {
      var assets = window.__STUDIO_STATE.assets;
      function specWith(kind) {
        return {
          name: "ok-name", title: "T", panels: [], kpis: [], filters: [],
          cda: { dataAccesses: kind ? [{ id: "d1", name: "d1", kind: kind, columns: ["x"], fileUrl: "https://x/y.parquet" }] : [] }
        };
      }
      var duckHtml = Studio.exportCDF(specWith("duckdb"), assets, "/x");
      var httpvfsHtml = Studio.exportCDF(specWith("httpvfs"), assets, "/x");
      var plainHtml = Studio.exportCDF(specWith(""), assets, "/x");
      return {
        duckdbHasFacade: /Studio\.DuckDB\s*=/.test(duckHtml),
        duckdbOmitsSqlite: !/Studio\.SQLiteHttp\s*=/.test(duckHtml),
        httpvfsHasFacade: /Studio\.SQLiteHttp\s*=/.test(httpvfsHtml),
        httpvfsOmitsDuckdb: !/Studio\.DuckDB\s*=/.test(httpvfsHtml),
        plainOmitsBoth: !/Studio\.DuckDB\s*=/.test(plainHtml) && !/Studio\.SQLiteHttp\s*=/.test(plainHtml)
      };
    });
    ok("Z14 fix: a duckdb-only export bundles the DuckDB façade but not the SQLite one", z14Bundling.duckdbHasFacade && z14Bundling.duckdbOmitsSqlite, JSON.stringify(z14Bundling));
